// Handle file upload from Odoo
const input = $input.item.json;
const config = $('Config (API Keys)').item.json;

// Check if this is a file upload or folder scan
if (input.action === 'upload_file' && input.file_data) {
  // Decode base64 file
  const fileBuffer = Buffer.from(input.file_data, 'base64');

  // Create binary data for next nodes
  const binaryData = await this.helpers.prepareBinaryData(
    fileBuffer,
    input.file_name || 'upload.pdf',
    'application/pdf'
  );

  return {
    json: {
      name: input.file_name,
      id: `odoo-upload-${Date.now()}`,
      odoo_log_id: input.odoo_log_id,
      triggered_by: input.triggered_by,
      _config: config
    },
    binary: { data: binaryData }
  };
} else {
  // Folder scan - return empty to skip (let OneDrive trigger handle it)
  return { json: { skip: true, message: 'Folder scan requested - use OneDrive trigger' } };
}
